function norm(s: string): string {
  return s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\./g, '').replace(/\s+/g, ' ').trim();
}

// Fuzzy index: "<first-initial>|<last-word>" and reversed order, ambiguous keys marked null
const FUZZY = new Map<string, number | null>();
function addFuzzy(k: string, v: number) {
  if (FUZZY.has(k) && FUZZY.get(k) !== v) FUZZY.set(k, null);
  else FUZZY.set(k, v);
}
for (const key of Object.keys(PRICE_OVERRIDES)) {
  const v = PRICE_OVERRIDES[key];
  const parts = key.split(' ');
  if (parts.length >= 2) {
    addFuzzy(parts[0][0] + '|' + parts[parts.length - 1], v);
    addFuzzy(parts[parts.length - 1][0] + '|' + parts[0], v);
  }
}

export function lookupPrice(name: string): number | undefined {
  const k = norm(name);
  if (PRICE_OVERRIDES[k] !== undefined) return PRICE_OVERRIDES[k];
  const parts = k.split(' ');
  if (parts.length >= 2) {
    const a = FUZZY.get(parts[0][0] + '|' + parts[parts.length - 1]);
    if (a !== null && a !== undefined) return a;
    const b = FUZZY.get(parts[parts.length - 1][0] + '|' + parts[0]);
    if (b !== null && b !== undefined) return b;
  }
  return undefined;
}
